+	const binaryDataService = mock<BinaryDataService>();
+	const controller = new BinaryDataController(binaryDataService);
+
+	describe('get', () => {
+		it('should throw BadRequestError for empty filesystem URI', async () => {
+			const req = mock<BinaryDataRequest>();
+			req.query = { id: 'filesystem://' } as any;
+
+			await expect(controller.get(req)).rejects.toThrow('Missing binary data ID');
+		});
+
+		it('should throw BadRequestError for empty filesystem-v2 URI', async () => {
+			const req = mock<BinaryDataRequest>();
+			req.query = { id: 'filesystem-v2://' } as any;
+
+			await expect(controller.get(req)).rejects.toThrow('Missing binary data ID');
+		});
+
+		it('should throw BadRequestError for filesystem URI with only whitespace', async () => {
+			const req = mock<BinaryDataRequest>();
+			req.query = { id: 'filesystem://   ' } as any;
+
+			await expect(controller.get(req)).rejects.toThrow('Missing binary data ID');
+		});
+
+		it('should process valid filesystem URI', async () => {
+			const req = mock<BinaryDataRequest>();
+			req.query = { id: 'filesystem://valid-id' } as any;
